"use client";

/**
 * Stack Component
 *
 * A flexible layout component for arranging children in a row or column
 * with consistent spacing using design system tokens.
 *
 * @example
 * ```tsx
 * // Vertical stack (default)
 * <Stack gap="md">
 *   <Card />
 *   <Card />
 * </Stack>
 *
 * // Horizontal stack
 * <Stack direction="horizontal" gap="sm" align="center">
 *   <Button>Save</Button>
 *   <Button variant="secondary">Cancel</Button>
 * </Stack>
 * ```
 */

import React from "react";
import type { StackProps } from "./Stack.types";
import styles from "./Stack.module.css";

export const Stack = React.forwardRef<HTMLElement, StackProps>(
  (
    {
      direction = "vertical",
      gap = "md",
      align = "stretch",
      justify = "flex-start",
      wrap = "nowrap",
      as: Component = "div",
      className,
      children,
      ...rest
    },
    ref,
  ) => {
    const classNames = [
      styles.stack,
      styles[direction],
      styles[`gap-${gap}`],
      styles[`align-${align}`],
      styles[`justify-${justify}`],
      styles[`wrap-${wrap}`],
      className,
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <Component ref={ref as any} className={classNames} {...rest}>
        {children}
      </Component>
    );
  },
);

Stack.displayName = "Stack";

/**
 * Stack Component Styles
 *
 * Flexible layout container for arranging children with consistent spacing.
 */

/* Base stack */
.stack {
  display: flex;
  box-sizing: border-box;
}

/* ============================================================================
 * DIRECTION
 * ============================================================================ */

.vertical {
  flex-direction: column;
}

.horizontal {
  flex-direction: row;
}

/* ============================================================================
 * GAP (Spacing between children using design tokens)
 * ============================================================================ */

.gap-xs {
  gap: var(--spacing-2); /* 8px */
}

.gap-sm {
  gap: var(--spacing-3); /* 12px */
}

.gap-md {
  gap: var(--spacing-4); /* 16px */
}

.gap-lg {
  gap: var(--spacing-6); /* 24px */
}

.gap-xl {
  gap: var(--spacing-8); /* 32px */
}

/* ============================================================================
 * ALIGN ITEMS
 * ============================================================================ */

.align-flex-start {
  align-items: flex-start;
}

.align-center {
  align-items: center;
}

.align-flex-end {
  align-items: flex-end;
}

.align-stretch {
  align-items: stretch;
}

.align-baseline {
  align-items: baseline;
}

/* ============================================================================
 * JUSTIFY CONTENT
 * ============================================================================ */

.justify-flex-start {
  justify-content: flex-start;
}

.justify-center {
  justify-content: center;
}

.justify-flex-end {
  justify-content: flex-end;
}

.justify-space-between {
  justify-content: space-between;
}

.justify-space-around {
  justify-content: space-around;
}

.justify-space-evenly {
  justify-content: space-evenly;
}

/* ============================================================================
 * WRAP
 * ============================================================================ */

.wrap-nowrap {
  flex-wrap: nowrap;
}

.wrap-wrap {
  flex-wrap: wrap;
}

.wrap-wrap-reverse {
  flex-wrap: wrap-reverse;
}

export { Stack } from "./Stack";
export type {
  StackProps,
  StackGap,
  StackDirection,
  StackAlign,
  StackJustify,
  StackWrap,
} from "./Stack.types";
